/// <summary>
///
/// </summary>
display AmountMST getTotalAmt()
{
    ETG_ChargeCodes eTG_ChargeCodesLoc;
    AgreementLine   agreementLine;
    PurchAgreementHeader purchAgreementHeader;
    AgreementLineQuantityCommitment agreementLineQuantityCommitment;

    select purchAgreementHeader where purchAgreementHeader.PurchNumberSequence == this.Estimation;
    if(purchAgreementHeader)
    {
        select agreementLine where agreementLine.Agreement == purchAgreementHeader.RecId;
    }
    select agreementLineQuantityCommitment where
        agreementLineQuantityCommitment.RecId == agreementLine.RecId;


    return agreementLineQuantityCommitment.CommitedQuantity * 
        agreementLineQuantityCommitment.PricePerUnit;
}

display AmountMST getTotalCharges()
{
    ETG_ChargeCodes eTG_ChargeCodesLoc;
    select  sum(AmountMST) from eTG_ChargeCodesLoc
        where eTG_ChargeCodesLoc.PurchNumberSequence == this.Estimation;
    return eTG_ChargeCodesLoc.AmountMST;
}

display AmountMST getSubTotal()
{
    return this.getTotalAmt() + this.getTotalCharges();
}

display AmountMST getActualTotalAmt()
{
    ETG_ActualagreementNew eTG_ActualagreementLoc;
    select  sum(AmountMST) from eTG_ActualagreementLoc
        where eTG_ActualagreementLoc.PurchNumberSequence == this.Estimation;
    return eTG_ActualagreementLoc.AmountMST;
}

display AmountMST getActualChargeAmt()
{
    ETG_ActualagreementNew eTG_ActualagreementLoc;
    select  sum(Value) from eTG_ActualagreementLoc
        where eTG_ActualagreementLoc.PurchNumberSequence == this.Estimation;
    return eTG_ActualagreementLoc.Value;
}

display AmountMST getActualSubTotal()
{
    return this.getActualTotalAmt() + this.getActualChargeAmt();
}
